<template>
  <div class="filter"></div>
  <div class="root">
    <header>
      <div class="offline" v-show="!isAliveSensor">сенсор недоступен</div>
      <div class="date">
        {{ time.date }}.{{ time.month }}.{{ time.year }}
        {{time.day }}
      </div>
      <div class="clock"><div>{{time.hour}}</div>
      <div class="blink"> 
            <div  v-show="time.blink">:</div>
      </div>
       <!-- :style="`: translateX(${trans+'px'})`" -->
       <div>{{time.min}}</div></div>
    </header>
     
      <div class="panel">
      <div class="sensor">
        <div class="value">
        Дом: <br> {{ sensors.inTemp }} °C
          
        </div>
        <div class="icon">

        </div>
      </div>
      <div class="sensor">
        <div class="value">
        Улица: <br> {{  sensors.outTemp }} °C
        </div>
        <div class="icon"></div>
      </div>
      <div class="sensor">
        <div class="value">
        Влажность: <br> {{  sensors.hum }} %
        </div>
        <div class="icon">

        </div>
      </div>
      <div class="sensor">
        <div class="value">
        Давление: <br> {{  sensors.press }} мм.рт.ст
        </div>
        <div class="icon"></div>
      </div>
    </div>
  </div>  
</template>

<script>
  export default {
    data(){
      return {
        sensors:{
          inTemp: null,
          inTempAHT: null,
          hum: null,
          outTemp: null,
          press: null,  
        },
        isAliveSensor: false,

        ws: null,
        
        time:{
          blink:false,
          hour:'',
          min:'',
          day:'',
          date:'',
          month: '',
          year:'', 
      }
      }
    },

    methods:{
          connect(){
          this.ws = new WebSocket('wss://peredaifile.ru:3031');

            this.ws.onmessage =  (event) => {
              let message = JSON.parse(event.data);
              console.log("сообщение от сервера!");
                if (message.type == 'sensors') {

                  this. sensors.inTemp = message.value.inTemp;
                  this. sensors.outTemp = message.value.outTemp;
                  this. sensors.press = message.value.press;

                  this. sensors.inTempAHT = message.value.inTempAHT;
                  this. sensors.hum = message.value.hum;

                  this.isAliveSensor = message.value.isAlive;

                }
              }
              // this.ws.onerror =  (event) => {
              //   console.log('WSerror');
              //   this.reconnect();
              // };
              this.ws.onclose =  (event) => {
                console.log('WSclose');
                this.reconnect();
              };
            },
            getTime(){
              let nowTime;
              let days = {
                0: 'ВС', 1: 'ПН', 2: 'ВТ', 3: 'СР', 4: 'ЧТ', 5: 'ПТ', 6: 'СБ',
              };
              let timer = ()=>{
                nowTime = new Date();
                this.time.hour = nowTime.getHours();
                this.time.min = nowTime.getMinutes();
                this.time.hour/10<1?this.time.hour='0'+this.time.hour:this.time.hour;
                this.time.min/10<1?this.time.min='0'+this.time.min:this.time.min;
                this.time.blink = !this.time.blink;
              };
              let dater = ()=>{
                nowTime = new Date();
                this.time.date = nowTime.getDate();
                this.time.month = nowTime.getMonth()+1;
                this.time.year = nowTime.getFullYear();
                this.time.day = days[nowTime.getDay()];
                this.time.date/10<1?this.time.date='0'+this.time.date:this.time.date;
                this.time.month/10<1?this.time.month='0'+this.time.month:this.time.month;
                
              };
              timer();
              dater();
            setInterval(()=>{
              timer()
              },1000);
            
            },
            reconnect(){
              this.ws = null;
                try {
                  setTimeout(()=> this.connect(),10000);
                }
                catch {console.log('Не удачно!')}
                            
            },
      },
      

    mounted(){
    this.getTime();
    this.connect();
    
    
    
  }
    
  }
</script>

